SET FOREIGN_KEY_CHECKS = 0;
CREATE TABLE IF NOT EXISTS categories (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(100) NOT NULL UNIQUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS users (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, email VARCHAR(150) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, role ENUM('admin','staff','customer') NOT NULL DEFAULT 'customer', status ENUM('active','inactive','suspended') NOT NULL DEFAULT 'active', phone VARCHAR(30) DEFAULT NULL, address TEXT DEFAULT NULL, profile_photo VARCHAR(255) DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS items (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(200) NOT NULL, category_id INT UNSIGNED NOT NULL, size VARCHAR(50) DEFAULT NULL, stock INT UNSIGNED NOT NULL DEFAULT 0, rental_price DECIMAL(10,2) NOT NULL DEFAULT 0.00, sale_price DECIMAL(10,2) NOT NULL DEFAULT 0.00, status ENUM('available','reserved','damaged','retired') NOT NULL DEFAULT 'available', image VARCHAR(255) DEFAULT NULL, description TEXT DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_item_category FOREIGN KEY (category_id) REFERENCES categories(id) ON UPDATE CASCADE ON DELETE RESTRICT) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS transactions (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, customer_id INT UNSIGNED NOT NULL, item_id INT UNSIGNED NOT NULL, staff_id INT UNSIGNED DEFAULT NULL, type ENUM('rent','sale') NOT NULL, status ENUM('pending','approved','rejected','active','overdue','returned','completed','cancelled') NOT NULL DEFAULT 'pending', borrow_date DATE DEFAULT NULL, due_date DATE DEFAULT NULL, return_date DATE DEFAULT NULL, penalty_fee DECIMAL(10,2) NOT NULL DEFAULT 0.00, amount_paid DECIMAL(10,2) NOT NULL DEFAULT 0.00, notes TEXT DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_txn_customer FOREIGN KEY (customer_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT fk_txn_item FOREIGN KEY (item_id) REFERENCES items(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT fk_txn_staff FOREIGN KEY (staff_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS return_notices (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, transaction_id INT UNSIGNED NOT NULL, customer_id INT UNSIGNED NOT NULL, notice_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP, pickup_status ENUM('pending_pickup','received','confirmed') NOT NULL DEFAULT 'pending_pickup', confirmed_by INT UNSIGNED DEFAULT NULL, confirmed_at TIMESTAMP DEFAULT NULL, CONSTRAINT fk_rn_transaction FOREIGN KEY (transaction_id) REFERENCES transactions(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_rn_customer FOREIGN KEY (customer_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE RESTRICT, CONSTRAINT fk_rn_confirmed_by FOREIGN KEY (confirmed_by) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS stock_history (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, item_id INT UNSIGNED NOT NULL, change INT NOT NULL, reason VARCHAR(255) NOT NULL, staff_id INT UNSIGNED DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_sh_item FOREIGN KEY (item_id) REFERENCES items(id) ON UPDATE CASCADE ON DELETE CASCADE, CONSTRAINT fk_sh_staff FOREIGN KEY (staff_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS logs (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id INT UNSIGNED DEFAULT NULL, action VARCHAR(100) NOT NULL, details TEXT DEFAULT NULL, ip VARCHAR(45) DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_log_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS notifications (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id INT UNSIGNED NOT NULL, message TEXT NOT NULL, type VARCHAR(60) NOT NULL DEFAULT 'info', is_read TINYINT(1) NOT NULL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_notif_user FOREIGN KEY (user_id) REFERENCES users(id) ON UPDATE CASCADE ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS availability (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, item_id INT UNSIGNED NOT NULL, blocked_from DATE NOT NULL, blocked_to DATE NOT NULL, reason VARCHAR(255) DEFAULT NULL, CONSTRAINT fk_avail_item FOREIGN KEY (item_id) REFERENCES items(id) ON UPDATE CASCADE ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS settings (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, key_name VARCHAR(100) NOT NULL UNIQUE, value TEXT NOT NULL, label VARCHAR(150) NOT NULL, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE INDEX idx_transactions_status ON transactions(status);
CREATE INDEX idx_transactions_due ON transactions(due_date);
CREATE INDEX idx_transactions_customer ON transactions(customer_id);
CREATE INDEX idx_notifications_user ON notifications(user_id, is_read);
CREATE INDEX idx_logs_user ON logs(user_id);
CREATE INDEX idx_items_status ON items(status);
